CREATE SCHEMA CRM;
GO
CREATE TABLE CRM.CUSTOMERS(CUSTOMER_ID BIGINT PRIMARY KEY, EMAIL NVARCHAR(255), PHONE NVARCHAR(20), FIRST_NAME NVARCHAR(100), LAST_NAME NVARCHAR(100), GENDER NVARCHAR(10), DATE_OF_BIRTH DATE, REGISTRATION_DATE DATETIME2, CUSTOMER_TYPE NVARCHAR(20), STATUS NVARCHAR(20), EMAIL_VERIFIED BIT, PHONE_VERIFIED BIT, MARKETING_OPT_IN BIT, PREFERRED_LANGUAGE NVARCHAR(20), CREATED_BY NVARCHAR(50), CREATED_DATE DATETIME2, LAST_UPDATE_DATE DATETIME2);
CREATE TABLE CRM.CUSTOMER_REGISTRATION_SOURCE(REGISTRATION_SOURCE_ID BIGINT PRIMARY KEY, CUSTOMER_ID BIGINT, CHANNEL NVARCHAR(50), CAMPAIGN_ID INT, UTM_SOURCE NVARCHAR(100), UTM_MEDIUM NVARCHAR(100), UTM_CAMPAIGN NVARCHAR(200), UTM_CONTENT NVARCHAR(200), REFERRER_URL NVARCHAR(500), LANDING_PAGE NVARCHAR(500), DEVICE_TYPE NVARCHAR(20), REGISTRATION_DATE DATETIME2, CREATED_DATE DATETIME2);
CREATE TABLE CRM.INCIDENTS(INCIDENT_ID BIGINT PRIMARY KEY, CUSTOMER_ID BIGINT, CATEGORY NVARCHAR(30), SEVERITY NVARCHAR(20), STATUS NVARCHAR(20), CREATED_DATE DATETIME2, RESOLVED_DATE DATETIME2);
CREATE TABLE CRM.INTERACTIONS(INTERACTION_ID BIGINT PRIMARY KEY, CUSTOMER_ID BIGINT, CHANNEL NVARCHAR(20), DIRECTION NVARCHAR(20), INTERACTION_DATE DATETIME2);
CREATE TABLE CRM.SURVEYS(SURVEY_ID BIGINT PRIMARY KEY, CUSTOMER_ID BIGINT, ORDER_ID BIGINT, INCIDENT_ID BIGINT, SURVEY_TYPE NVARCHAR(20), NPS_SCORE TINYINT, CSAT_SCORE TINYINT, NPS_CATEGORY NVARCHAR(20), FEEDBACK_TEXT NVARCHAR(MAX), FEEDBACK_CATEGORY NVARCHAR(50), RESPONSE_DATE DATETIME2, CREATED_DATE DATETIME2);
GO
